import React from 'react';
import { Link } from 'react-router-dom';

const Navbar = () => {

  return (
    <nav className='navbar navbar-expand-lg navbar-dark bg-primary shadow'>
      <div className='container'>
        <Link className='navbar-brand navbar-brand text-shadow' to='/'>
          rent-a-car.ru
        </Link>
        <button
          className='navbar-toggler'
          type='button'
          data-mdb-toggle='collapse'
          data-mdb-target='#navbarRightAlignExample'
        >
          <i className='fas fa-bars'></i>
        </button>
        <div className='collapse navbar-collapse' id='navbarRightAlignExample'>
          <ul className='navbar-nav ms-auto mb-2 mb-lg-0'>
            <li className='nav-item'>
              <Link className='nav-link text-white' to='/find'>
                Поиск
              </Link>
            </li>

            <li className='nav-item dropdown'>
              <a className='nav-link text-white' type='button'>
                Язык: <strong>RU</strong>
              </a>
              <ul className='dropdown-menu'>
                <li>
                  <a className='dropdown-item' href='#'>
                    RU
                  </a>
                </li>
                <li>
                  <a className='dropdown-item' href='#'>
                    ENG
                  </a>
                </li>
              </ul>
            </li>

            <li className='nav-item dropdown'>
              <a className='nav-link text-white' type='button'>
                Валюта: <strong>RUB</strong>
              </a>
              <ul className='dropdown-menu'>
                <li>
                  <a className='dropdown-item' href='#'>
                    RUB
                  </a>
                </li>
                <li>
                  <a className='dropdown-item' href='#'>
                    USD
                  </a>
                </li>
                <li>
                  <a className='dropdown-item' href='#'>
                    EUR
                  </a>
                </li>
              </ul>
            </li>

            <li className='nav-item'>
              <a className='nav-link text-white sign-up' href='#'>
                Войти
              </a>
            </li>
          </ul>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
